namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly object _lock = new();

    public List<Notification> GetInitialNotifications()
    {
        lock (_lock)
        {
            var notifications = new List<Notification>
            {
                new(_nextId++, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)),
                new(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)),
                new(_nextId++, "New comment on your post.", DateTime.UtcNow.AddMinutes(-2)),
            };
            return notifications;
        }
    }

    public List<Notification> CheckForNew(int afterId)
    {
        lock (_lock)
        {
            // Simulate new notifications arriving randomly
            if (Random.Shared.Next(0, 3) == 0) // ~33% chance each poll
            {
                var messages = new[]
                {
                    "Someone liked your post.",
                    "You have a new follower!",
                    "Deployment completed successfully.",
                    "Reminder: meeting in 15 minutes.",
                    "Your export is ready to download.",
                };

                var msg = messages[Random.Shared.Next(messages.Length)];
                return [new Notification(_nextId++, msg, DateTime.UtcNow)];
            }

            return [];
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR — this data is included in the
        // server-rendered HTML and reused when the component becomes interactive.
        _notifications = NotificationService.GetInitialNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is interactive in
            // the browser, so the polling loop never runs during static SSR.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
            var newItems = NotificationService.CheckForNew(lastId);

            if (newItems.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    _notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

